theme.custom_css_code:
.pc-diagram-box {
  width: 100%;
  padding: 20px;
  border-radius: 22px;
  border: 1px solid rgba(255,255,255,0.12);
  background: rgba(255,255,255,0.05);
  backdrop-filter: blur(4px);
  font-family: Arial, sans-serif;
}

.pc-diagram-row + .pc-diagram-row {
  margin-top: 16px;
}

.pc-diagram-label {
  margin-bottom: 8px;
  font-size: 14px;
  font-weight: 700;
  line-height: 1.4;
  color: #f5d7ff;
}

.pc-diagram-bar {
  width: 100%;
  height: 16px;
  border-radius: 999px;
  background: rgba(255,255,255,0.10);
  overflow: hidden;
  position: relative;
}

.pc-diagram-fill {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  height: 100%;
  min-width: 52px;
  padding-right: 8px;
  border-radius: 999px;
  background: linear-gradient(90deg, #f0a9ff 0%, #ffd3ff 100%);
  box-shadow: 0 0 18px rgba(255,211,255,0.28);
}

.pc-diagram-fill span {
  font-size: 11px;
  font-weight: 700;
  color: #4d255f;
}

@media (max-width: 575px) {
  .pc-diagram-box {
    padding: 16px;
  }

  .pc-diagram-label {
    font-size: 13px;
  }

  .pc-diagram-bar {
    height: 14px;
  }
}
.pc-games-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 16px;
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.pc-game-card {
  position: relative;
  overflow: hidden;
  min-height: 190px;
  padding: 18px;
  border-radius: 22px;
  border: 1px solid rgba(255,255,255,0.12);
  background: linear-gradient(180deg, rgba(255,255,255,0.08), rgba(255,255,255,0.04));
  box-shadow: 0 10px 30px rgba(0,0,0,0.18);
}

.pc-game-card::after {
  content: "";
  position: absolute;
  inset: auto -20px -35px auto;
  width: 110px;
  height: 110px;
  border-radius: 50%;
  background: rgba(255,255,255,0.07);
  filter: blur(2px);
}

.pc-game-icon {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 18px;
  height: 42px;
}

.pc-game-card-slots .pc-game-icon span {
  width: 22px;
  height: 34px;
  border-radius: 8px;
  background: linear-gradient(180deg, #ffd4ff, #f195ff);
  box-shadow: inset 0 -6px 0 rgba(100,58,118,0.25);
}

.pc-live-icon span:first-child {
  width: 38px;
  height: 38px;
  border: 3px solid #ffd9ff;
  border-radius: 50%;
}

.pc-live-icon span:last-child {
  width: 12px;
  height: 12px;
  margin-left: -10px;
  border-radius: 50%;
  background: #ffb4f8;
}

.pc-jackpot-icon span {
  width: 42px;
  height: 42px;
  background: linear-gradient(180deg, #ffe9a8, #ffbf47);
  clip-path: polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%);
}

.pc-instant-icon span:first-child {
  width: 38px;
  height: 26px;
  border-radius: 8px;
  background: linear-gradient(180deg, #ffd8fd, #eaa3ff);
}

.pc-instant-icon span:last-child {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: #fff;
  margin-left: -24px;
}

.pc-game-name {
  font-size: 20px;
  line-height: 1.2;
  font-weight: 700;
  color: #ffffff;
  margin-bottom: 10px;
}

.pc-game-text {
  font-size: 14px;
  line-height: 1.55;
  color: #f3e2fb;
  max-width: 260px;
}

@media (max-width: 991px) {
  .pc-games-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 575px) {
  .pc-games-grid {
    grid-template-columns: 1fr;
  }

  .pc-game-card {
    min-height: 0;
  }
}
.pc-brand-table-wrap {
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.pc-brand-table-scroll {
  width: 100%;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  border: 1px solid rgba(255,255,255,0.14);
  border-radius: 18px;
  background: rgba(255,255,255,0.05);
  backdrop-filter: blur(4px);
}

.pc-brand-table {
  width: 100%;
  min-width: 640px;
  border-collapse: collapse;
  color: #f7eefb;
}

.pc-brand-table td {
  padding: 14px 16px;
  border-bottom: 1px solid rgba(255,255,255,0.1);
  vertical-align: top;
  font-size: 14px;
  line-height: 1.5;
}

.pc-brand-table tr:last-child td {
  border-bottom: none;
}

.pc-brand-table td:first-child {
  width: 220px;
  color: #f1cfff;
  font-weight: 700;
  background: rgba(255,255,255,0.03);
}

.pc-brand-table td:last-child {
  color: #ffffff;
}

@media (max-width: 767px) {
  .pc-brand-table td {
    padding: 12px 14px;
    font-size: 13px;
  }
}
